    @Body('status') status: string,
  ) {
    return await this.adminService.updateUserStatus(userId, status);
  }

  @Get('activity')
  async getRecentActivity(@Query('limit') limit?: string) {
    const limitNumber = limit ? parseInt(limit, 10) : 10;
    return await this.adminService.getRecentActivity(limitNumber);
  }
}

import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { User } from '../users/entities/user.entity';
import { Chat } from '../chat/entities/chat.entity';
import { Message } from '../chat/entities/message.entity';

@Injectable()
export class AdminService {
  constructor(
    @InjectRepository(User)
    private userRepository: Repository<User>,
    @InjectRepository(Chat)
    private chatRepository: Repository<Chat>,
    @InjectRepository(Message)
    private messageRepository: Repository<Message>,
  ) {}

  // Ejemplo de método con tipado correcto
  async getDashboardStats() {
    const totalUsers = await this.userRepository.count();
    const totalChats = await this.chatRepository.count();
    const totalMessages = await this.messageRepository.count();

    return {
      totalUsers,
      totalChats,
      totalMessages,
    };
  }

  // Corrección para los métodos que causaban errores
  async getUserActivity() {
    const users = await this.userRepository.find({
      select: ['id', 'email', 'name', 'role', 'createdAt'],
    });

    return users.map((user) => ({
      userId: user.id,
      email: user.email,
      name: user.name,
      role: user.role,
      createdAt: user.createdAt,
    }));
  }

  async getChatActivity() {
    const chats = await this.chatRepository.find({
      relations: ['user', 'messages'],
    });

    return chats.map((chat) => ({
      chatId: chat.id,
      userId: chat.user?.id,
      userEmail: chat.user?.email,
      messageCount: chat.messages?.length || 0,
      lastMessage: chat.messages?.[chat.messages.length - 1]?.content,
      createdAt: chat.createdAt,
    }));
  }
}

import { Controller, Post, Body, UseGuards, Request } from '@nestjs/common';
import { AuthService } from './auth.service';
